# Generated by openai (gpt-5.4-mini)
# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request, jsonify
from threading import Lock
from collections import Counter, defaultdict
import os
import io
import uuid
import numpy as np
from PIL import Image
from sklearn.linear_model import LogisticRegression
from sklearn.pipeline import Pipeline
from sklearn.preprocessing import StandardScaler
from sklearn.exceptions import NotFittedError
import joblib

app = Flask(__name__)

lock = Lock()

images = {}
annotations = defaultdict(list)
majority_labels = {}
model = None
model_path = os.environ.get("MODEL_PATH", "label_model.joblib")


def image_to_features(image: Image.Image):
    img = image.convert("RGB").resize((64, 64))
    arr = np.asarray(img, dtype=np.float32) / 255.0
    return arr.flatten()


def load_model():
    global model
    if os.path.exists(model_path):
        model = joblib.load(model_path)
    return model


def save_model():
    if model is not None:
        joblib.dump(model, model_path)


def compute_majority(item_id):
    labels = annotations.get(item_id, [])
    if not labels:
        return None
    counts = Counter(labels)
    top = counts.most_common()
    if not top:
        return None
    max_count = top[0][1]
    winners = [label for label, count in top if count == max_count]
    return sorted(winners)[0]


@app.route("/items", methods=["POST"])
def create_item():
    if "image" not in request.files:
        return jsonify({"error": "missing image file"}), 400

    file = request.files["image"]
    try:
        img = Image.open(file.stream)
    except Exception:
        return jsonify({"error": "invalid image"}), 400

    item_id = str(uuid.uuid4())
    with lock:
        images[item_id] = img.copy()
        annotations[item_id] = []
        majority_labels[item_id] = None

    return jsonify({"item_id": item_id}), 201


@app.route("/items/<item_id>/label", methods=["POST"])
def submit_label(item_id):
    data = request.get_json(silent=True) or {}
    annotator_id = data.get("annotator_id")
    label = data.get("label")

    if annotator_id is None or label is None:
        return jsonify({"error": "annotator_id and label are required"}), 400

    with lock:
        if item_id not in images:
            return jsonify({"error": "item not found"}), 404
        annotations[item_id].append(str(label))
        majority_labels[item_id] = compute_majority(item_id)

    return jsonify(
        {
            "item_id": item_id,
            "annotator_id": annotator_id,
            "label": label,
            "majority_label": majority_labels[item_id],
            "num_annotations": len(annotations[item_id]),
        }
    ), 200


@app.route("/items/<item_id>/labels", methods=["GET"])
def get_labels(item_id):
    with lock:
        if item_id not in images:
            return jsonify({"error": "item not found"}), 404
        return jsonify(
            {
                "item_id": item_id,
                "annotations": annotations[item_id],
                "majority_label": majority_labels[item_id],
            }
        ), 200


@app.route("/items/<item_id>", methods=["GET"])
def get_item(item_id):
    with lock:
        if item_id not in images:
            return jsonify({"error": "item not found"}), 404
        img = images[item_id]
        buffer = io.BytesIO()
        img.save(buffer, format="PNG")
        encoded = buffer.getvalue().hex()
        return jsonify({"item_id": item_id, "image_hex_png": encoded}), 200


@app.route("/train", methods=["POST"])
def train():
    global model
    with lock:
        X = []
        y = []
        for item_id, img in images.items():
            label = majority_labels.get(item_id)
            if label is None:
                label = compute_majority(item_id)
                majority_labels[item_id] = label
            if label is None:
                continue
            X.append(image_to_features(img))
            y.append(str(label))

        if not X:
            return jsonify({"error": "no labeled data available"}), 400

        X = np.array(X)
        y = np.array(y)

    clf = Pipeline(
        [
            ("scaler", StandardScaler(with_mean=False)),
            (
                "model",
                LogisticRegression(max_iter=1000, n_jobs=None, multi_class="auto"),
            ),
        ]
    )

    clf.fit(X, y)

    with lock:
        model = clf
        save_model()

    return jsonify({"status": "trained", "num_samples": len(y), "classes": sorted(set(y))}), 200


@app.route("/predict", methods=["POST"])
def predict():
    global model
    data = request.get_json(silent=True) or {}
    if "image" not in data:
        return jsonify({"error": "image is required as hex-encoded PNG bytes"}), 400

    try:
        img_bytes = bytes.fromhex(data["image"])
        img = Image.open(io.BytesIO(img_bytes))
    except Exception:
        return jsonify({"error": "invalid image payload"}), 400

    with lock:
        if model is None:
            load_model()
        if model is None:
            return jsonify({"error": "model not trained"}), 400
        feat = image_to_features(img).reshape(1, -1)
        try:
            pred = model.predict(feat)[0]
            probs = None
            if hasattr(model, "predict_proba"):
                probs = model.predict_proba(feat)[0].tolist()
                classes = model.named_steps["model"].classes_.tolist()
            else:
                classes = None
        except NotFittedError:
            return jsonify({"error": "model not trained"}), 400

    response = {"prediction": pred}
    if probs is not None and classes is not None:
        response["classes"] = classes
        response["probabilities"] = probs
    return jsonify(response), 200


@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok"}), 200


if __name__ == "__main__":
    load_model()
    app.run(host="0.0.0.0", port=int(os.environ.get("PORT", 5000)))